class Solution:
    def minMaxSubarraySum(self, nums, k):
        n = len(nums)
        total = 0
        for l in range(n):
            for r in range(l, min(n, l + k)):
                sub = nums[l:r + 1]
                total += max(sub) + min(sub)
        return total

