var minMaxSubarraySum = function(nums, k) {
    const n = nums.length;
    function bounds(strictLeftPop, strictRightPop) {
        const left = new Array(n).fill(-1);
        let stack = [];
        for (let i = 0; i < n; i++) {
            while (stack.length && (strictLeftPop ? nums[stack[stack.length - 1]] <= nums[i] : nums[stack[stack.length - 1]] >= nums[i])) {
                stack.pop();
            }
            left[i] = stack.length ? stack[stack.length - 1] : -1;
            stack.push(i);
        }
        const right = new Array(n).fill(n);
        stack = [];
        for (let i = n - 1; i >= 0; i--) {
            while (stack.length && (strictRightPop ? nums[stack[stack.length - 1]] < nums[i] : nums[stack[stack.length - 1]] > nums[i])) {
                stack.pop();
            }
            right[i] = stack.length ? stack[stack.length - 1] : n;
            stack.push(i);
        }
        return [left, right];
    }
    const [LMax, RMax] = bounds(true, true);
    const [LMin, RMin] = bounds(false, false);
    function contrib(i, L, R) {
        const lowL = Math.max(L + 1, i - k + 1);
        let total = 0;
        const part1Hi = Math.min(i, R - k);
        if (part1Hi >= lowL) {
            const cnt1 = part1Hi - lowL + 1;
            total += cnt1 * (k - i) + Math.floor((lowL + part1Hi) * cnt1 / 2);
        }
        const part2Lo = Math.max(lowL, R - k + 1);
        if (part2Lo <= i) {
            const cnt2 = i - part2Lo + 1;
            total += cnt2 * (R - i);
        }
        return total;
    }
    let ans = 0;
    for (let i = 0; i < n; i++) {
        ans += nums[i] * (contrib(i, LMax[i], RMax[i]) + contrib(i, LMin[i], RMin[i]));
    }
    return ans;
};
